 71→    private String createTaskJson(String title, String description, String priority) {
 72→        StringBuilder sb = new StringBuilder("{");
 73→        boolean hasField = false;
 74→        if (title != null) {
 75→            sb.append("\"title\":\"").append(title).append("\"");
 76→            hasField = true;
 77→        }
 78→        if (description != null) {
 79→            if (hasField) sb.append(",");
 80→            sb.append("\"description\":\"").append(description).append("\"");
 81→            hasField = true;
 82→        }
 83→        if (priority != null) {
 84→            if (hasField) sb.append(",");
 85→            sb.append("\"priority\":\"").append(priority).append("\"");
 86→        }
 87→        sb.append("}");
 88→        return sb.toString();
 89→    }
 90→
 91→    private String updateTaskJson(String title, String description, String priority) {
 92→        return createTaskJson(title, description, priority);
 93→    }
