 95→    /**
 96→     * Creates a task via the API and returns the response body as JsonNode.
 97→     */
 98→    private JsonNode createTaskViaApi(String title, String description, String priority) throws Exception {
 99→        String body = createTaskJson(title, description, priority);
100→        MvcResult result = mockMvc.perform(post("/api/tasks")
101→                        .header("Authorization", "Bearer " + authToken)
102→                        .contentType(MediaType.APPLICATION_JSON)
103→                        .content(body))
104→                .andExpect(status().isCreated())
105→                .andReturn();
106→        return objectMapper.readTree(result.getResponse().getContentAsString());
107→    }
