111→     */
112→    private Task createTaskInDb(String title, Task.Priority priority) {
113→        Task task = new Task();
114→        task.setTitle(title);
115→        task.setDescription("Description for " + title);
116→        task.setPriority(priority);
117→        task.setCreatedBy(testUserId);
118→        return taskRepository.save(task);
119→    }
