package com.taskflow.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.entity.Task;
import com.taskflow.entity.User;
import com.taskflow.repository.TaskRepository;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;
import org.junit.jupiter.api.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import static org.assertj.core.api.Assertions.assertThat;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Integration tests for TaskController — M2 Task CRUD.
 *
 * Covers all 16 acceptance criteria (AC1-AC16) from M2-task-crud spec.
 * Uses full Spring Boot context with MockMvc to test through security filter chain.
 *
 * Tests will FAIL until TaskService, TaskController, UpdateTaskRequest,
 * PageResponse, and GlobalExceptionHandler are implemented.
 */
@SpringBootTest
@AutoConfigureMockMvc
@DisplayName("TaskController Integration Tests (M2 Task CRUD)")
class TaskControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String authToken;
    private Long testUserId;

    @BeforeEach
    void setUp() {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        User user = new User();
        user.setUsername("testuser");
        user.setPassword("encoded_password");
        user.setDisplayName("Test User");
        user = userRepository.save(user);
        testUserId = user.getId();

        authToken = jwtTokenProvider.generateToken(testUserId);
    }

    // ── Helper methods ──────────────────────────────────────────────────

    private String createTaskJson(String title, String description, String priority) {
        StringBuilder sb = new StringBuilder("{");
        boolean hasField = false;
        if (title != null) {
            sb.append("\"title\":\"").append(title).append("\"");
            hasField = true;
        }
        if (description != null) {
            if (hasField) sb.append(",");
            sb.append("\"description\":\"").append(description).append("\"");
            hasField = true;
        }
        if (priority != null) {
            if (hasField) sb.append(",");
            sb.append("\"priority\":\"").append(priority).append("\"");
        }
        sb.append("}");
        return sb.toString();
    }

    private String updateTaskJson(String title, String description, String priority) {
        return createTaskJson(title, description, priority);
    }

    /**
     * Creates a task via the API and returns the response body as JsonNode.
     */
    private JsonNode createTaskViaApi(String title, String description, String priority) throws Exception {
        String body = createTaskJson(title, description, priority);
        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isCreated())
                .andReturn();
        return objectMapper.readTree(result.getResponse().getContentAsString());
    }

    /**
     * Creates a task directly in the DB for setup purposes.
     */
    private Task createTaskInDb(String title, Task.Priority priority) {
        Task task = new Task();
        task.setTitle(title);
        task.setDescription("Description for " + title);
        task.setPriority(priority);
        task.setCreatedBy(testUserId);
        return taskRepository.save(task);
    }

    // ── AC1: POST /api/tasks with valid token → 201 ─────────────────────

    @Nested
    @DisplayName("AC1: Create task with valid token and all fields")
    class AC1_CreateTask {

        @Test
        @DisplayName("POST /api/tasks with title+description+priority returns 201 with full task")
        void shouldCreateTaskWith201() throws Exception {
            String body = createTaskJson("My New Task", "Task description", "HIGH");

            MvcResult result = mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isCreated())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("id")).isNotNull();
            assertThat(response.get("id").asLong()).isGreaterThan(0);
            assertThat(response.get("title").asText()).isEqualTo("My New Task");
            assertThat(response.get("description").asText()).isEqualTo("Task description");
            assertThat(response.get("priority").asText()).isEqualTo("HIGH");
            assertThat(response.get("status").asText()).isEqualTo("TODO");
            assertThat(response.get("createdBy").asLong()).isEqualTo(testUserId);
            assertThat(response.get("createdAt")).isNotNull();
            assertThat(response.get("createdAt").asText()).isNotEmpty();
        }
    }

    // ── AC2: POST without priority → defaults to MEDIUM ─────────────────

    @Nested
    @DisplayName("AC2: Create task without priority defaults to MEDIUM")
    class AC2_DefaultPriority {

        @Test
        @DisplayName("POST /api/tasks without priority field sets priority to MEDIUM")
        void shouldDefaultToMediumPriority() throws Exception {
            String body = "{\"title\":\"Task Without Priority\",\"description\":\"desc\"}";

            MvcResult result = mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isCreated())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("priority").asText()).isEqualTo("MEDIUM");
        }
    }

    // ── AC3: POST without title or empty title → 400 ────────────────────

    @Nested
    @DisplayName("AC3: Create task without title or empty title returns 400")
    class AC3_MissingTitle {

        @Test
        @DisplayName("POST /api/tasks without title field returns 400")
        void shouldReturn400WhenTitleMissing() throws Exception {
            String body = "{\"description\":\"desc\",\"priority\":\"HIGH\"}";

            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("POST /api/tasks with empty title returns 400")
        void shouldReturn400WhenTitleEmpty() throws Exception {
            String body = "{\"title\":\"\",\"description\":\"desc\"}";

            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());
        }

        @Test
        @DisplayName("POST /api/tasks with blank (whitespace-only) title returns 400")
        void shouldReturn400WhenTitleBlank() throws Exception {
            String body = "{\"title\":\"   \",\"description\":\"desc\"}";

            mockMvc.perform(post("/api/tasks")
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(body))
                    .andExpect(status().isBadRequest());
        }
    }

    // ── AC4: GET /api/tasks/{id} existing → 200 ─────────────────────────

    @Nested
    @DisplayName("AC4: Get existing task by ID returns 200 with full task")
    class AC4_GetById {

        @Test
        @DisplayName("GET /api/tasks/{id} for existing task returns 200 with full task object")
        void shouldReturn200WithFullTask() throws Exception {
            JsonNode created = createTaskViaApi("Test Task", "Test Description", "HIGH");
            long taskId = created.get("id").asLong();

            MvcResult result = mockMvc.perform(get("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("id").asLong()).isEqualTo(taskId);
            assertThat(response.get("title").asText()).isEqualTo("Test Task");
            assertThat(response.get("description").asText()).isEqualTo("Test Description");
            assertThat(response.get("priority").asText()).isEqualTo("HIGH");
            assertThat(response.get("status").asText()).isEqualTo("TODO");
            assertThat(response.get("createdBy").asLong()).isEqualTo(testUserId);
            assertThat(response.get("createdAt")).isNotNull();
        }
    }

    // ── AC5: GET /api/tasks/{id} non-existent → 404 ─────────────────────

    @Nested
    @DisplayName("AC5: Get non-existent task returns 404")
    class AC5_GetNonExistent {

        @Test
        @DisplayName("GET /api/tasks/{id} for non-existent ID returns 404")
        void shouldReturn404ForNonExistentTask() throws Exception {
            mockMvc.perform(get("/api/tasks/{id}", 99999L)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound());
        }
    }

    // ── AC6: PUT /api/tasks/{id} → 200 + updatedAt has value ────────────

    @Nested
    @DisplayName("AC6: Update task returns 200 with updated content and updatedAt")
    class AC6_UpdateTask {

        @Test
        @DisplayName("PUT /api/tasks/{id} with updates returns 200 with updated task")
        void shouldUpdateTaskAndReturn200() throws Exception {
            JsonNode created = createTaskViaApi("Original Title", "Original Desc", "LOW");
            long taskId = created.get("id").asLong();

            String updateBody = updateTaskJson("Updated Title", "Updated Desc", "HIGH");

            MvcResult result = mockMvc.perform(put("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(updateBody))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("title").asText()).isEqualTo("Updated Title");
            assertThat(response.get("description").asText()).isEqualTo("Updated Desc");
            assertThat(response.get("priority").asText()).isEqualTo("HIGH");
            assertThat(response.get("updatedAt")).isNotNull();
            assertThat(response.get("updatedAt").isNull()).isFalse();
        }

        @Test
        @DisplayName("PUT /api/tasks/{id} for non-existent task returns 404")
        void shouldReturn404WhenUpdatingNonExistentTask() throws Exception {
            String updateBody = updateTaskJson("Updated Title", "Updated Desc", "HIGH");

            mockMvc.perform(put("/api/tasks/{id}", 99999L)
                            .header("Authorization", "Bearer " + authToken)
                            .contentType(MediaType.APPLICATION_JSON)
                            .content(updateBody))
                    .andExpect(status().isNotFound());
        }
    }

    // ── AC7: DELETE /api/tasks/{id} → 204 No Content ────────────────────

    @Nested
    @DisplayName("AC7: Delete task returns 204 and soft-deletes")
    class AC7_DeleteTask {

        @Test
        @DisplayName("DELETE /api/tasks/{id} returns 204 No Content")
        void shouldReturn204OnDelete() throws Exception {
            JsonNode created = createTaskViaApi("Task To Delete", "desc", "MEDIUM");
            long taskId = created.get("id").asLong();

            mockMvc.perform(delete("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());
        }

        @Test
        @DisplayName("DELETE /api/tasks/{id} soft-deletes the task in DB")
        void shouldSoftDeleteTaskInDb() throws Exception {
            JsonNode created = createTaskViaApi("Task To Delete", "desc", "MEDIUM");
            long taskId = created.get("id").asLong();

            mockMvc.perform(delete("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            // Verify the task is soft-deleted in DB (still exists but deleted=true)
            Task task = taskRepository.findById(taskId).orElse(null);
            assertThat(task).isNotNull();
            assertThat(task.isDeleted()).isTrue();
        }

        @Test
        @DisplayName("DELETE /api/tasks/{id} for non-existent task returns 404")
        void shouldReturn404WhenDeletingNonExistentTask() throws Exception {
            mockMvc.perform(delete("/api/tasks/{id}", 99999L)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound());
        }
    }

    // ── AC8: Soft-deleted task NOT in GET /api/tasks list ────────────────

    @Nested
    @DisplayName("AC8: Soft-deleted tasks excluded from task list")
    class AC8_SoftDeletedNotInList {

        @Test
        @DisplayName("GET /api/tasks does not return soft-deleted tasks")
        void shouldExcludeSoftDeletedFromList() throws Exception {
            createTaskViaApi("Active Task 1", "desc1", "HIGH");
            createTaskViaApi("Active Task 2", "desc2", "MEDIUM");

            // Create and delete a task
            JsonNode deletedTask = createTaskViaApi("Deleted Task", "desc3", "LOW");
            long deletedId = deletedTask.get("id").asLong();
            mockMvc.perform(delete("/api/tasks/{id}", deletedId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            // List tasks — should only have 2
            MvcResult result = mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isOk())
                    .andReturn();

            JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
            assertThat(response.get("totalElements").asLong()).isEqualTo(2);
            JsonNode content = response.get("content");
            assertThat(content.isArray()).isTrue();
            assertThat(content.size()).isEqualTo(2);
        }
    }

    // ── AC9: GET /api/tasks/{id} for soft-deleted → 404 ─────────────────

    @Nested
    @DisplayName("AC9: Get soft-deleted task by ID returns 404")
    class AC9_GetSoftDeleted {

        @Test
        @DisplayName("GET /api/tasks/{id} for soft-deleted task returns 404")
        void shouldReturn404ForSoftDeletedTask() throws Exception {
            JsonNode created = createTaskViaApi("Task To Delete", "desc", "MEDIUM");
            long taskId = created.get("id").asLong();

            // Delete the task
            mockMvc.perform(delete("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNoContent());

            // Attempt to get the deleted task
            mockMvc.perform(get("/api/tasks/{id}", taskId)
                            .header("Authorization", "Bearer " + authToken))
                    .andExpect(status().isNotFound());
        }
    }

    // ── AC10: GET /api/tasks no params → paginated, defaults ────────────

    @Nested
    @DisplayName("AC10: List tasks with default pagination")
    class AC10_DefaultPagination {

        @Test
