package com.taskflow.dto;

import com.taskflow.entity.Task;
import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Validation tests for UpdateTaskRequest DTO.
 *
 * Tests will FAIL until UpdateTaskRequest is implemented.
 * Expected fields: title (required, 1-200), description (optional, max 5000), priority (optional).
 */
@DisplayName("UpdateTaskRequest Validation Tests")
class UpdateTaskRequestValidationTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    private UpdateTaskRequest createValid() {
        UpdateTaskRequest req = new UpdateTaskRequest();
        req.setTitle("Valid Title");
        req.setDescription("Valid description");
        req.setPriority(Task.Priority.HIGH);
        return req;
    }

    @Nested
    @DisplayName("Title validation")
    class TitleValidation {

        @Test
        @DisplayName("Valid title passes validation")
        void validTitlePasses() {
            UpdateTaskRequest req = createValid();
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Null title fails validation")
        void nullTitleFails() {
            UpdateTaskRequest req = createValid();
            req.setTitle(null);
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Empty title fails validation")
        void emptyTitleFails() {
            UpdateTaskRequest req = createValid();
            req.setTitle("");
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Blank (whitespace) title fails validation")
        void blankTitleFails() {
            UpdateTaskRequest req = createValid();
            req.setTitle("   ");
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isNotEmpty();
        }

        @Test
        @DisplayName("Title with exactly 200 chars passes validation")
        void title200CharsPasses() {
            UpdateTaskRequest req = createValid();
            req.setTitle("a".repeat(200));
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Title with 201 chars fails validation")
        void title201CharsFails() {
            UpdateTaskRequest req = createValid();
            req.setTitle("a".repeat(201));
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isNotEmpty();
        }
    }

    @Nested
    @DisplayName("Description validation")
    class DescriptionValidation {

        @Test
        @DisplayName("Null description passes validation (optional)")
        void nullDescriptionPasses() {
            UpdateTaskRequest req = createValid();
            req.setDescription(null);
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Description with 5000 chars passes validation")
        void description5000CharsPasses() {
            UpdateTaskRequest req = createValid();
            req.setDescription("a".repeat(5000));
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("Description with 5001 chars fails validation")
        void description5001CharsFails() {
            UpdateTaskRequest req = createValid();
            req.setDescription("a".repeat(5001));
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isNotEmpty();
        }
    }

    @Nested
    @DisplayName("Priority validation")
    class PriorityValidation {

        @Test
        @DisplayName("Null priority passes validation (optional)")
        void nullPriorityPasses() {
            UpdateTaskRequest req = createValid();
            req.setPriority(null);
            Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
            assertThat(violations).isEmpty();
        }

        @Test
        @DisplayName("All priority values are accepted")
        void allPriorityValuesAccepted() {
            for (Task.Priority p : Task.Priority.values()) {
                UpdateTaskRequest req = createValid();
                req.setPriority(p);
                Set<ConstraintViolation<UpdateTaskRequest>> violations = validator.validate(req);
                assertThat(violations).isEmpty();
            }
        }
    }
}

