import java.util.List;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Unit tests for PageResponse DTO.
 *
 * Tests will FAIL until PageResponse is implemented.
 * Expected fields: content (List<T>), page (int), size (int), totalElements (long), totalPages (int).
 */
@DisplayName("PageResponse DTO Tests")
class PageResponseTest {

    @Test
    @DisplayName("Should store and return content list")
    void shouldStoreContent() {
        PageResponse<String> response = new PageResponse<>();
        List<String> items = List.of("item1", "item2", "item3");
        response.setContent(items);
        assertThat(response.getContent()).isEqualTo(items);
        assertThat(response.getContent()).hasSize(3);
    }

    @Test
    @DisplayName("Should store and return page number")
    void shouldStorePage() {
        PageResponse<String> response = new PageResponse<>();
        response.setPage(2);
        assertThat(response.getPage()).isEqualTo(2);
    }

    @Test
    @DisplayName("Should store and return page size")
    void shouldStoreSize() {
        PageResponse<String> response = new PageResponse<>();
        response.setSize(20);
        assertThat(response.getSize()).isEqualTo(20);
    }

    @Test
    @DisplayName("Should store and return total elements")
    void shouldStoreTotalElements() {
        PageResponse<String> response = new PageResponse<>();
        response.setTotalElements(100L);
        assertThat(response.getTotalElements()).isEqualTo(100L);
    }

    @Test
    @DisplayName("Should store and return total pages")
    void shouldStoreTotalPages() {
        PageResponse<String> response = new PageResponse<>();
        response.setTotalPages(5);
        assertThat(response.getTotalPages()).isEqualTo(5);
    }

    @Test
    @DisplayName("Should handle empty content list")
    void shouldHandleEmptyContent() {
        PageResponse<String> response = new PageResponse<>();
        response.setContent(List.of());
        response.setPage(0);
        response.setSize(20);
        response.setTotalElements(0L);
        response.setTotalPages(0);

        assertThat(response.getContent()).isEmpty();
        assertThat(response.getTotalElements()).isEqualTo(0L);
    }
}

