package com.taskflow.exception;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.taskflow.entity.User;
import com.taskflow.repository.TaskRepository;
import com.taskflow.repository.UserRepository;
import com.taskflow.security.JwtTokenProvider;

import org.junit.jupiter.api.BeforeEach;

import static org.assertj.core.api.Assertions.assertThat;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.*;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

/**
 * Integration tests for GlobalExceptionHandler.
 *
 * Tests will FAIL until GlobalExceptionHandler is implemented.
 * Verifies error response format: {status, message, errors?}
 *
 * @see com.taskflow.exception.GlobalExceptionHandler
 */
@SpringBootTest
@AutoConfigureMockMvc
@DisplayName("GlobalExceptionHandler Tests")
class GlobalExceptionHandlerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TaskRepository taskRepository;

    private String authToken;

    @BeforeEach
    void setUp() {
        taskRepository.deleteAll();
        userRepository.deleteAll();

        User user = new User();
        user.setUsername("testuser");
        user.setPassword("encoded_password");
        user.setDisplayName("Test User");
        user = userRepository.save(user);

        authToken = jwtTokenProvider.generateToken(user.getId());
    }

    @Test
    @DisplayName("Validation error (400) returns structured error with status and message")
    void validationErrorReturnsStructuredResponse() throws Exception {
        // POST with empty body (missing required title)
        String body = "{}";

        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isBadRequest())
                .andReturn();

        JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
        assertThat(response.has("status")).isTrue();
        assertThat(response.get("status").asInt()).isEqualTo(400);
        assertThat(response.has("message")).isTrue();
        assertThat(response.get("message").asText()).isNotEmpty();
    }

    @Test
    @DisplayName("Validation error (400) may include errors array for field-level details")
    void validationErrorMayIncludeErrorsArray() throws Exception {
        String body = "{}";

        MvcResult result = mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isBadRequest())
                .andReturn();

        JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
        // The errors field is optional per the CONTRACT error format
        // If present, it should be an array
        if (response.has("errors")) {
            assertThat(response.get("errors").isArray()).isTrue();
        }
    }

    @Test
    @DisplayName("Not found error (404) returns structured error with status and message")
    void notFoundErrorReturnsStructuredResponse() throws Exception {
        MvcResult result = mockMvc.perform(get("/api/tasks/{id}", 99999L)
                        .header("Authorization", "Bearer " + authToken))
                .andExpect(status().isNotFound())
                .andReturn();

        JsonNode response = objectMapper.readTree(result.getResponse().getContentAsString());
        assertThat(response.has("status")).isTrue();
        assertThat(response.get("status").asInt()).isEqualTo(404);
        assertThat(response.has("message")).isTrue();
        assertThat(response.get("message").asText()).isNotEmpty();
    }

    @Test
    @DisplayName("Multiple validation errors returns 400 with details")
    void multipleValidationErrorsReturn400() throws Exception {
        // title > 200 chars
        String longTitle = "a".repeat(201);
        String longDesc = "a".repeat(5001);
        String body = "{\"title\":\"" + longTitle + "\",\"description\":\"" + longDesc + "\"}";

        mockMvc.perform(post("/api/tasks")
                        .header("Authorization", "Bearer " + authToken)
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(body))
                .andExpect(status().isBadRequest());
    }
}

